// notNull14 is the sorted subset of the 21 FOCUS 1.4 Mandatory columns that
// are ALSO non-null (15) — the exact set the pipeline's validation enforces
// row by row (validate.go). A 1.4-declared file must carry all of these.
var notNull14 = []string{
	"BilledCost", "BillingAccountId", "BillingCurrency", "BillingPeriodEnd", "BillingPeriodStart",
	"ChargeCategory", "ChargePeriodEnd", "ChargePeriodStart", "ContractedCost", "EffectiveCost",
	"InvoiceIssuerName", "ListCost", "ServiceCategory", "ServiceName", "ServiceProviderName",
}

// mandatoryNullable14 is the sorted remainder of the 21 FOCUS 1.4 Mandatory
// columns — Mandatory-presence but nullable (6). Their absence from a 1.4
// file is a WARNING, not a failure.
var mandatoryNullable14 = []string{
	"BillingAccountName", "ChargeClass", "ChargeDescription", "HostProviderName", "PricingQuantity", "PricingUnit",
}

// knownColumnsFor returns the known-column set for a supported version. Every
// accepted version needs an explicit case: the default arm returns the 65-column
// 1.4 set (knownColumns14), a superset — so a 1.0/1.1 file falling through to it
// would wrongly accept columns absent from its declared version (e.g. InvoiceId,
// first added in 1.2, or ServiceProviderName, added in 1.3) as known.
func knownColumnsFor(v focus.Version) map[string]struct{} {
	switch v {
	case focus.V1_0:
		return toSet(knownColumns10)
	case focus.V1_1:
		return toSet(knownColumns11)
	case focus.V1_2:
		return toSet(knownColumns12)
	case focus.V1_3:
		return toSet(knownColumns13)
	default: // V1_4 (ParseVersion has already rejected everything else)
		return toSet(knownColumns14)
	}
}

// mandatoryFor returns the sorted Mandatory-presence set for a 1.0/1.1/1.2/1.3
// file (1.4 uses notNull14 + mandatoryNullable14 directly). FOCUS 1.0, 1.1, and
// 1.2 share the SAME 21-column Mandatory set byte-for-byte (verified against the
// v1.0/v1.1 tags: ProviderName/PublisherName are Mandatory in all three and
// 1.0/1.1 carry none of 1.3's added Mandatory columns), so all three resolve to
// mandatory12. Every non-1.2 case needs an explicit arm: 1.0/1.1 must NOT fall
// through to mandatory13 (23 columns), which requires the 1.3-only successors.
func mandatoryFor(v focus.Version) []string {
	switch v {
	case focus.V1_0, focus.V1_1, focus.V1_2:
		return mandatory12
	default: // V1_3
		return mandatory13
	}
}

func toSet(cols []string) map[string]struct{} {
	set := make(map[string]struct{}, len(cols))
	for _, c := range cols {
		set[c] = struct{}{}
	}
	return set
}
